mapper.select:
/* CNSTSC_EXCCLC_Dao_retrieveCnstscExcclcList */
, BASIN_MAPPING_LIST AS (
) SELECT MAX(dscfc_lclhq_cd) AS dscfc_lclhq_cd, MAX(basin_nm) AS dscfc_lclhq_nm, dscfc_bplc_cd, MAX(dscfc_bplc_nm) AS dscfc_bplc_nm, ROUND(NVL(SUM(dscfc_usgqty), 0), 2) AS usgqty, ROUND(NVL(SUM(tot_amt), 0), 2) AS amt, MAX(basin_sort_ordr) AS basin_sort_ordr, MAX(dscfc_bplc_sort_ordr) AS dscfc_bplc_sort_ordr FROM ( SELECT dscfc_lclhq_cd, dscfc_lclhq_nm, ( SELECT cmmn_cd_nm FROM BASIN_MAPPING_LIST WHERE DECODE(objid, '10000000', '20060557', '50029610', '10990028', objid) = dscfc_lclhq_cd ) AS basin_nm, ( SELECT sort_ordr FROM BASIN_MAPPING_LIST WHERE DECODE(objid, '10000000', '20060557', '50029610', '10990028', objid) = dscfc_lclhq_cd ) AS basin_sort_ordr, dscfc_bplc_cd, dscfc_bplc_nm, dscfc_bplc_sort_ordr, dscfc_usgqty, tot_amt FROM GHG_DATA_LIST WHERE 1 = 1
AND dscfc_bplc_cd = #{ecsChrgDeptId}
AND dscfc_use_de BETWEEN SUBSTR(#{strtDt}, 0, 6) AND SUBSTR(#{endDt}, 0, 6)
) GROUP BY dscfc_bplc_cd ORDER BY basin_sort_ordr, dscfc_bplc_sort_ordr
